<template>
  <div class="demo-card" :style="bgImage">
    <h2 class="card-title">{{ title }}</h2>
    <p class="card-desc">{{ desc }}</p>
  </div>
</template>

<script>
export default {
  props: {
    title: String,
    desc: String,
    images: Array,
  },

  computed: {
    bgImage() {
      return { "--bg-image-url": `url(${this.images[0]})` };
    },
  },
};
</script>

<style lang="scss" scoped>
.demo-card {
  width: 50%;
  height: 50%;

  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;

  color: #ffffff;

  background-image: var(--bg-image-url);
}
</style>
